-- Senha padrão: Blumen@2025 (sha256 com salt)
-- salt: blumensalt2025
-- hash: blumensalt2025Blumen@2025 -> sha256

-- Super Admin: Camila Arnuti
INSERT INTO users (id, email, name, role, password_hash, is_active, tenant_id, created_at)
VALUES (
  'b0000000-0000-0000-0000-000000000001',
  'camila@blumenbiz.com',
  'Camila Arnuti',
  'admin',
  'blumensalt2025:' || encode(sha256(convert_to('blumensalt2025Blumen@2025', 'UTF8')), 'hex'),
  true,
  'a0000000-0000-0000-0000-000000000001',
  NOW()
) ON CONFLICT (email) DO UPDATE SET
  role = 'admin',
  is_active = true,
  password_hash = 'blumensalt2025:' || encode(sha256(convert_to('blumensalt2025Blumen@2025', 'UTF8')), 'hex');

